class EncryptionService {
  constructor() {
    this.key = this._deriveKey(ENCRYPTION_KEY, ENCRYPTION_SALT);
    this.iv = CryptoJS.enc.Utf8.parse(ENCRYPTION_IV);
  }

  _deriveKey(passphrase, salt) {
    return CryptoJS.PBKDF2(passphrase, salt, {
      keySize: 256 / 32,
      iterations: ITERATIONS,
      hasher: CryptoJS.algo.SHA256,
    });
  }

  encrypt(data) {
    try {
      if (data === null || data === undefined) {
        throw new Error('Data to encrypt cannot be null or undefined');
      }

      const stringData = typeof data === 'string' ? data : JSON.stringify(data);

      const encrypted = CryptoJS.AES.encrypt(stringData, this.key, {
        iv: this.iv,
        mode: CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7,
      });

      return encrypted.toString();
    } catch (error) {
      console.error('Encryption error:', error.message);
      throw new Error(`Encryption failed: ${error.message}`);
    }
  }

  decrypt(encryptedData) {
    try {
      if (!encryptedData || typeof encryptedData !== 'string') {
        throw new Error('Invalid encrypted data');
      }

      const decrypted = CryptoJS.AES.decrypt(encryptedData, this.key, {
        iv: this.iv,
        mode: CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7,
      });

      const decryptedString = decrypted.toString(CryptoJS.enc.Utf8);

      if (!decryptedString) {
        throw new Error('Decryption produced empty result - possibly wrong key');
      }

      return decryptedString;
    } catch (error) {
      console.error('Decryption error:', error.message);
      throw new Error(`Decryption failed: ${error.message}`);
    }
  }

  decryptToObject(encryptedData) {
    try {
      const decryptedString = this.decrypt(encryptedData);
      return JSON.parse(decryptedString);
    } catch (error) {
      if (error.message.includes('Decryption failed')) {
        throw error;
      }
      throw new Error(`Failed to parse decrypted data as JSON: ${error.message}`);
    }
  }

  generateHash(data) {
    const stringData = typeof data === 'string' ? data : JSON.stringify(data);
    return CryptoJS.SHA256(stringData).toString();
  }

  generateHMAC(data) {
    const stringData = typeof data === 'string' ? data : JSON.stringify(data);
    return CryptoJS.HmacSHA256(stringData, ENCRYPTION_KEY).toString();
  }

  verifyHMAC(data, hmac) {
    const computedHmac = this.generateHMAC(data);
    return computedHmac === hmac;
  }
}

