// hooks/useSecureStorage.js
import { useState, useCallback, useEffect } from 'react';
import secureStorage from '../utils/secureStorage';

export function useSecureStorage() {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const execute = useCallback(async (operation) => {
    setLoading(true);
    setError(null);
    try {
      const result = await operation();
      setLoading(false);
      return result;
    } catch (err) {
      setError(err.message);
      setLoading(false);
      throw err;
    }
  }, []);

  const saveUserProfile = useCallback(
    (profile) => execute(() => secureStorage.saveUserProfile(profile)),
    [execute]
  );

  const getUserProfile = useCallback(
    () => execute(() => secureStorage.getUserProfile()),
    [execute]
  );

  const savePaymentInfo = useCallback(
    (paymentData) => execute(() => secureStorage.savePaymentInfo(paymentData)),
    [execute]
  );

  const getPaymentInfo = useCallback(
    () => execute(() => secureStorage.getPaymentInfo()),
    [execute]
  );

  const addPaymentCard = useCallback(
    (card) => execute(() => secureStorage.addPaymentCard(card)),
    [execute]
  );

  const removePaymentCard = useCallback(
    (cardId) => execute(() => secureStorage.removePaymentCard(cardId)),
    [execute]
  );

  const saveAuthToken = useCallback(
    (tokenData) => execute(() => secureStorage.saveAuthToken(tokenData)),
    [execute]
  );

  const getAuthToken = useCallback(
    () => execute(() => secureStorage.getAuthToken()),
    [execute]
  );

  const isAuthenticated = useCallback(
    () => execute(() => secureStorage.isAuthenticated()),
    [execute]
  );

  const logout = useCallback(
    () => execute(() => secureStorage.performSecureLogout()),
    [execute]
  );

  const wipeAllData = useCallback(
    () => execute(() => secureStorage.performFullDataWipe()),
    [execute]
  );

  const savePin = useCallback(
    (pin) => execute(() => secureStorage.savePinHash(pin)),
    [execute]
  );

  const verifyPin = useCallback(
    (pin) => execute(() => secureStorage.verifyPin(pin)),
    [execute]
  );

  return {
    loading,
    error,
    saveUserProfile,
    getUserProfile,
    savePaymentInfo,
    getPaymentInfo,
    addPaymentCard,
    removePaymentCard,
    saveAuthToken,
    getAuthToken,
    isAuthenticated,
    logout,
    wipeAllData,
    savePin,
    verifyPin,
  };
}

// hooks/useAuth.js
import { useState, useEffect, useCallback } from 'react';
import secureStorage from '../utils/secureStorage';

export function useAuth() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [authToken, setAuthToken] = useState(null);
  const [loading, setLoading] = useState(true);

  const checkAuth = useCallback(async () => {
    setLoading(true);
    try {
      const authenticated = await secureStorage.isAuthenticated();
      setIsLoggedIn(authenticated);
      if (authenticated) {
        const token = await secureStorage.getAuthToken();
        setAuthToken(token);
      }
    } catch {
      setIsLoggedIn(false);
      setAuthToken(null);
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    checkAuth();
  }, [checkAuth]);

  const login = useCallback(async (tokenData) => {
    await secureStorage.saveAuthToken(tokenData);
    setAuthToken(tokenData);
    setIsLoggedIn(true);
  }, []);

  const logout = useCallback(async () => {
    await secureStorage.performSecureLogout();
    setAuthToken(null);
    setIsLoggedIn(false);
  }, []);

  const refreshAuth = useCallback(async () => {
    await checkAuth();
  }, [checkAuth]);

  return {
    isLoggedIn,
    authToken,
    loading,
    login,
    logout,
    refreshAuth,
  };
}

